#include <bits/stdc++.h>
using namespace std;
const int maxn=1e6+5;
#define int long long
int n,k,cnt,f[maxn],w[maxn],v[maxn];
deque<int> dq;
int a[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>k;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	for(int i=1;i<=n;i++){
		while(dq.size()&&a[dq.back()]>=a[i]){
			dq.pop_back();
		}
		dq.push_back(i);
		if(dq.front()<=i-k){
			dq.pop_front();
		}
		if(i>=k){
			cout<<a[dq.front()]<<" ";
		}
	}
	cout<<"\n";
	dq.clear();
	for(int i=1;i<=n;i++){
		while(dq.size()&&a[dq.back()]<=a[i]){
			dq.pop_back();
		}
		dq.push_back(i);
		if(dq.front()<=i-k){
			dq.pop_front();
		}
		if(i>=k){
			cout<<a[dq.front()]<<" ";
		}
	}
	return 0;
}
